{
  "formal_minutes": {
    "meeting_meta": {
      "project_code": "PUBLIC_MEETING_SMOKE",
      "meeting_title": "UI Theme Package Release Readiness",
      "participants": [
        "Minjun",
        "Seoyeon",
        "Doyun",
        "Hara"
      ]
    },
    "confirmed_decisions": [
      {
        "topic": "공개 릴리스 목표 시점",
        "decision": "스모크 테스트가 통과할 경우 금요일 15:00 KST를 공개 릴리스 목표 시점으로 한다.",
        "conditions": [
          "스모크 테스트 통과"
        ],
        "source_certainty": "confirmed"
      },
      {
        "topic": "packageName mismatch 대응 원칙",
        "decision": "packageName mismatch가 발생하면 먼저 package config를 확인하고, 계약 자체가 잘못된 경우에만 스크립트 검토를 진행한다.",
        "source_certainty": "confirmed"
      }
    ],
    "rejected_proposals": [
      {
        "proposal": "smoke-theme-pack.mjs에서 packageName mismatch를 무시하도록 변경하자",
        "outcome": "rejected",
        "source_certainty": "confirmed"
      }
    ],
    "internal_stretch_goals": [
      {
        "goal": "수요일 릴리스",
        "status": "내부 스트레치 목표일 뿐 확정 공개 일정은 아님",
        "source_certainty": "confirmed"
      },
      {
        "goal": "README 설치 단계는 가능하면 목요일까지 검토",
        "status": "희망 일정이며 담당자 미지정",
        "source_certainty": "confirmed"
      }
    ],
    "non_decisions": [
      {
        "topic": "README install steps 검토",
        "note": "필요성은 언급되었으나 담당자 확정 없음",
        "source_certainty": "confirmed"
      }
    ],
    "risks": [
      {
        "risk": "생성된 tarball 경로가 잘못되면 릴리스가 지연될 수 있다.",
        "source_certainty": "confirmed"
      },
      {
        "risk": "README 설치 단계가 오래되어 있으면 릴리스 노트가 사용자에게 오해를 줄 수 있다.",
        "source_certainty": "confirmed"
      }
    ],
    "open_questions": [
      {
        "question": "최종 릴리스 승인 권한자는 누구인가?",
        "status": "unresolved",
        "source_certainty": "confirmed"
      },
      {
        "question": "릴리스 노트에 내부 수요일 스트레치 목표를 언급해야 하는가?",
        "status": "unresolved",
        "source_certainty": "confirmed"
      }
    ]
  },
  "action_items": [
    {
      "owner": "Minjun",
      "task": "금요일 10:00 KST까지 스모크 테스트를 재실행하고 결과를 공유한다.",
      "due": "금요일 10:00 KST",
      "status": "confirmed_open",
      "source_certainty": "confirmed"
    },
    {
      "owner": "Doyun",
      "task": "금요일 12:00 KST까지 action_items.md에 실패 트리아지 노트를 작성한다.",
      "due": "금요일 12:00 KST",
      "status": "confirmed_open",
      "source_certainty": "confirmed"
    },
    {
      "owner": "unassigned",
      "task": "README install steps를 가능하면 목요일까지 검토한다.",
      "due": "목요일 가능 시",
      "status": "proposed_unassigned",
      "source_certainty": "confirmed"
    },
    {
      "owner": "Hara",
      "task": "Minjun의 스모크 결과 공유 후 생성된 tarball 경로를 확인한다.",
      "due": "not specified",
      "status": "confirmed_open",
      "source_certainty": "confirmed"
    }
  ],
  "followup_note": {
    "check_next": [
      "Minjun의 스모크 테스트 통과 여부를 확인한다.",
      "스모크 통과 시 공개 릴리스 목표가 금요일 15:00 KST로 유지되는지 확인한다.",
      "Doyun의 failure triage note 작성 여부를 확인한다.",
      "Minjun의 결과 공유 이후 Hara의 tarball 경로 점검 결과를 확인한다.",
      "README install steps 검토 담당자를 지정할지 확인한다.",
      "최종 릴리스 승인 권한자를 확인한다.",
      "릴리스 노트에 수요일 스트레치 목표를 언급할지 결정한다."
    ],
    "do_not_invent": [
      "고객명 또는 외부 파트너",
      "예산 정보",
      "보안 사고",
      "프로덕션 장애",
      "법무 승인 요구",
      "지정되지 않은 담당자",
      "명시되지 않은 마감일"
    ]
  },
  "non_invention_rules": [
    "고객, 외부 파트너, 예산, 보안 사고, 장애, 법무 요구사항을 추가로 만들지 않는다.",
    "명시되지 않은 owner와 deadline은 확정 사실처럼 쓰지 않는다.",
    "수요일 릴리스는 확정 결정이 아니라 내부 스트레치 목표로만 기록한다.",
    "거절된 제안과 확정된 결정은 분리해서 기록한다.",
    "공개 안전 synthetic fixture에 없는 사실은 추론으로 보강하지 않는다."
  ]
}
